function documents_quote_import_admin_snapshot(): array { $u = function_exists('current_user') ? current_user() : ['id'=>'test','name'=>'Test User','role_name'=>'admin']; return ['id'=>(string)($u['id']??''),'name'=>(string)($u['name']??$u['username']??$u['full_name']??''),'role'=>(string)($u['role_name']??'')]; }
function documents_quote_import_required_columns(): array { return ['import_key','customer_name','customer_mobile','party_type','template_set','system_type','selected_model_number','main_solar_kwp','non_dcr_kwp','quotation_date','valid_until','scenario_price_self_funded','scenario_price_loan_upto_2_lacs','scenario_price_loan_above_2_lacs']; }
function documents_quote_import_optional_columns(): array { return ['consumer_account_no','billing_address','site_address','district','city','state','pin','meter_number','meter_serial_number','area_or_locality','sanctioned_load_kw','phase','average_monthly_units','shadow_free_area_sqft','monthly_bill_rs','unit_rate_rs_per_kwh','annual_generation_per_kw','subsidy_amount','transportation_amount','discount_amount','special_requests_text','email','gstin','pan','pricing_mode','place_of_supply_state','tax_profile_id','show_tax_breakup','primary_finance_scenario','loan_upto_2_lacs_margin_money_rs','loan_upto_2_lacs_loan_amount_rs','loan_upto_2_lacs_interest_pct','loan_upto_2_lacs_tenure_years','loan_above_2_lacs_margin_money_rs','loan_above_2_lacs_loan_amount_rs','loan_above_2_lacs_interest_pct','loan_above_2_lacs_tenure_years']; }
function documents_quote_import_template_headers(): array { return array_merge(documents_quote_import_required_columns(), documents_quote_import_optional_columns()); }
function documents_quote_import_safe_csv_cell($value): string { $v=(string)$value; return preg_match('/^[=+\-@]/',$v) ? "'".$v : $v; }
function documents_quote_import_row_hash(array $row): string { ksort($row); return hash('sha256', json_encode($row, JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)); }
function documents_quote_import_normalize_mobile(string $mobile): string { return documents_normalize_whatsapp_mobile($mobile) ?: preg_replace('/\D+/', '', $mobile); }
function documents_quote_import_batches(): array { $rows=[]; foreach (glob(documents_quote_import_batches_dir().'/*.json') ?: [] as $file) { $r=json_load($file,[]); if(is_array($r)) $rows[]=$r; } usort($rows, fn($a,$b)=>strcmp((string)($b['created_at']??''),(string)($a['created_at']??''))); return $rows; }
function documents_quote_import_load_batch(string $batchId): ?array { $p=documents_quote_import_batch_path($batchId); if(!is_file($p)) return null; $r=json_load($p,[]); return is_array($r)?$r:null; }
function documents_quote_import_save_batch(array $batch): array { $id=safe_filename((string)($batch['batch_id']??'')); if($id==='') return ['ok'=>false,'error'=>'Missing batch ID']; return json_save(documents_quote_import_batch_path($id), $batch); }
function documents_quote_import_existing_identities(): array { $keys=[];$hashes=[];$likely=[]; foreach (documents_list_quotes() as $q) { $m=is_array($q['import_metadata']??null)?$q['import_metadata']:[]; if((string)($m['import_key']??'')!=='') $keys[(string)$m['import_key']] = (string)($q['id']??''); if((string)($m['row_hash']??'')!=='') $hashes[(string)$m['row_hash']] = (string)($q['id']??''); $mob=documents_quote_import_normalize_mobile((string)($q['customer_mobile']??'')); $date=(string)($q['quotation_date']??''); $model=(string)($q['selected_model_number']??''); $amt=(string)round((float)($q['input_total_gst_inclusive']??$q['calc']['grand_total']??0),2); if($mob!==''&&$date!==''&&$model!==''&&$amt!=='0') $likely[$mob.'|'.$date.'|'.$model.'|'.$amt]=(string)($q['id']??''); } return ['keys'=>$keys,'hashes'=>$hashes,'likely'=>$likely]; }

function documents_quote_bool_from_csv($value, bool $default = true): bool { $v=strtolower(trim((string)$value)); if($v==='') return $default; return in_array($v, ['1','true','yes','y','on','enabled','enable'], true); }
function documents_quote_import_segment_codes(): array { return ['RES'=>true,'COM'=>true,'IND'=>true,'INST'=>true]; }
function documents_quote_import_normalize_input(array $input): array {
    $out=$input;
    $map=['non_dcr_kwp'=>'complimentary_non_dcr_kwp','sanctioned_load_kw'=>'sanction_load_kwp','subsidy_amount'=>'subsidy_expected_rs','transportation_amount'=>'transportation_rs','discount_amount'=>'discount_rs','phase'=>'hybrid_phase'];
    foreach($map as $from=>$to){ if(array_key_exists($from,$out) && !array_key_exists($to,$out)) $out[$to]=$out[$from]; }
    if(!array_key_exists('complimentary_non_dcr_kwp',$out)) $out['complimentary_non_dcr_kwp']='0';
    $pt=strtolower(trim((string)($out['party_type']??'lead')));
    $segHint='';
    $upper=strtoupper(trim((string)($out['party_type']??'')));
    if(isset(documents_quote_import_segment_codes()[$upper])) { $segHint=$upper; $pt='lead'; }
    $out['party_type']=in_array($pt,['customer','lead'],true)?$pt:'lead';
    if($segHint!=='' && trim((string)($out['segment']??''))==='') $out['segment']=$segHint;
    if(trim((string)($out['show_tax_breakup']??''))==='') $out['show_tax_breakup']='1';
    if(trim((string)($out['pricing_mode']??''))==='') $out['pricing_mode']='solar_split_70_30';
    if(trim((string)($out['place_of_supply_state']??''))==='') $out['place_of_supply_state']='Jharkhand';
    if(trim((string)($out['primary_finance_scenario']??''))==='') $out['primary_finance_scenario']='self_funded';
    return $out;
}
function documents_validate_quote_draft_input(array $input, array $context = []): array {
