    foreach($required as $col){ if(trim((string)($input[$col]??''))==='') $messages[]=['field'=>$col,'message'=>'Required field is missing.']; }
    $rawParty=strtoupper(trim((string)($input['_raw_party_type']??$context['raw_party_type']??'')));
    if($rawParty==='' && isset($context['source']) && ($context['source']==='csv')) $rawParty=strtoupper(trim((string)($_POST['party_type']??'')));
    $origParty=strtoupper(trim((string)($context['original_party_type']??'')));
    $partyCheck=$origParty!==''?$origParty:strtoupper(trim((string)($input['party_type_original']??$input['party_type_raw']??'')));
    if($partyCheck!=='' && isset(documents_quote_import_segment_codes()[$partyCheck])) $warnings[]=['field'=>'party_type','message'=>'Legacy segment code '.$partyCheck.' was treated as a segment hint; party_type was normalized to lead.'];
    if(!in_array((string)($input['party_type']??''), ['customer','lead'], true)) $messages[]=['field'=>'party_type','message'=>'party_type must be customer or lead.'];
    foreach(['quotation_date','valid_until'] as $d){ $v=(string)($input[$d]??''); if($v!=='' && !preg_match('/^\d{4}-\d{2}-\d{2}$/',$v)) $messages[]=['field'=>$d,'message'=>'Use ISO date YYYY-MM-DD.']; }
    $main=(float)($input['main_solar_kwp']??0); $non=(float)($input['complimentary_non_dcr_kwp']??$input['non_dcr_kwp']??0); if($main<0||$non<0||($main+$non)<=0) $messages[]=['field'=>'main_solar_kwp','message'=>'Total capacity must be greater than zero.'];
    $mobile=documents_quote_import_normalize_mobile((string)($input['customer_mobile']??'')); if($mobile==='') $messages[]=['field'=>'customer_mobile','message'=>'Valid mobile is required.'];
    $hash=documents_quote_import_row_hash($input); $ids=documents_quote_import_existing_identities(); $key=(string)($input['import_key']??'');
    if($key!=='' && isset($ids['keys'][$key])) $messages[]=['field'=>'import_key','message'=>'Import key already committed in quotation '.$ids['keys'][$key].'.'];
    if(isset($ids['hashes'][$hash])) $messages[]=['field'=>'row_hash','message'=>'This exact row was already committed in quotation '.$ids['hashes'][$hash].'.'];
    $likelyKey=$mobile.'|'.(string)($input['quotation_date']??'').'|'.(string)($input['selected_model_number']??'').'|'.(string)round((float)($input['scenario_price_self_funded']??0),2); if(isset($ids['likely'][$likelyKey])) $warnings[]=['field'=>'duplicate','message'=>'Likely duplicate of quotation '.$ids['likely'][$likelyKey].'.'];
    $preview=documents_build_quote_draft_from_input($input, ['dry_run'=>true]+$context);
    if(!empty($preview['system_reconcile_error'])) $warnings[]=['field'=>'kit','message'=>(string)$preview['system_reconcile_error']];
    return ['ok'=>$messages===[],'status'=>$messages? 'Error' : ($warnings?'Warning':'Valid'),'messages'=>array_merge($messages,$warnings),'errors'=>$messages,'warnings'=>$warnings,'row_hash'=>$hash,'normalized_mobile'=>$mobile,'preview'=>documents_quote_import_preview_from_quote($preview),'normalized_input'=>$input];
}
