    $q['finance_inputs']=['monthly_bill_rs'=>(string)($input['monthly_bill_rs']??''),'unit_rate_rs_per_kwh'=>(string)($input['unit_rate_rs_per_kwh']??''),'annual_generation_per_kw'=>(string)($input['annual_generation_per_kw']??''),'subsidy_expected_rs'=>(string)$sub,'transportation_rs'=>(string)$trans,'discount_rs'=>(string)$disc,'loan'=>['enabled'=>str_starts_with($primary,'loan_')]];
