    $input=is_array($validated['normalized_input']??null)?$validated['normalized_input']:(is_array($validated['input']??null)?$validated['input']:$validated); $quote=documents_build_quote_draft_from_input($input,$context); $seg=(string)($quote['segment']??'RES'); if((string)($quote['quote_no']??'')===''){ $num=documents_generate_quote_number($seg); if(empty($num['ok'])) return ['ok'=>false,'error'=>(string)($num['error']??'Numbering failed')]; $quote['quote_no']=(string)$num['quote_no']; }
    $quote['import_metadata']=['batch_id'=>(string)($context['batch_id']??''),'import_key'=>(string)($input['import_key']??''),'source_row'=>(int)($context['source_row']??0),'source_filename'=>safe_filename((string)($context['source_filename']??'')),'row_hash'=>(string)($validated['row_hash']??documents_quote_import_row_hash($input)),'importing_admin'=>documents_quote_import_admin_snapshot(),'imported_at'=>documents_quote_import_now()];
    $hashQuote=$quote; unset($hashQuote['import_metadata']['post_import_hash']); $quote['import_metadata']['post_import_hash']=hash('sha256', json_encode($hashQuote, JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)); $saved=documents_save_quote($quote); return !empty($saved['ok']) ? ['ok'=>true,'quote'=>$quote,'quote_id'=>$quote['id']] : ['ok'=>false,'error'=>(string)($saved['error']??'Save failed')];
}
function documents_quote_repair_imported_batch(array $batch): array { $repaired=0;$skipped=0;$failed=0;$reasons=[]; foreach((array)($batch['created_quotation_ids']??[]) as $qid){ $q=documents_get_quote((string)$qid); if(!$q){$skipped++;$reasons[$qid]='Quotation not found';continue;} $st=strtolower((string)($q['status']??'draft')); if($st!=='draft'||!empty($q['accepted_at'])||!empty($q['workflow']['agreement_id'])||!empty($q['workflow']['invoice_id'])){$skipped++;$reasons[$qid]='Not an eligible untouched draft';continue;} $meta=is_array($q['import_metadata']??null)?$q['import_metadata']:[]; $row=null; foreach((array)($batch['rows']??[]) as $r){ if((string)($r['commit_result']??'')!=='' && str_contains((string)$r['commit_result'],(string)$qid)){$row=$r;break;} if((string)($r['input']['import_key']??'')===(string)($meta['import_key']??'')){$row=$r;break;} } if(!$row||!is_array($row['input']??null)){$skipped++;$reasons[$qid]='Saved import input missing';continue;} $before=$q; $new=documents_build_quote_draft_from_input($row['input'],['preserve_id'=>$q['id'],'preserve_quote_no'=>$q['quote_no'],'preserve_created_at'=>$q['created_at']]); $new['import_metadata']=$meta; $new['public_token']=$q['public_token']??''; $new['public_share_token']=$q['public_share_token']??''; $new['public_url']=$q['public_url']??''; $new['repair_metadata']=['batch_id'=>(string)($batch['batch_id']??''),'actor'=>documents_quote_import_admin_snapshot(),'time'=>documents_quote_import_now(),'pre_repair_snapshot'=>$before,'before_hash'=>hash('sha256',json_encode($before,JSON_UNESCAPED_SLASHES|JSON_UNESCAPED_UNICODE)),'after_hash'=>hash('sha256',json_encode($new,JSON_UNESCAPED_SLASHES|JSON_UNESCAPED_UNICODE))]; $save=documents_save_quote($new); if(!empty($save['ok']))$repaired++;else{$failed++;$reasons[$qid]='Save failed';} } return ['repaired'=>$repaired,'skipped'=>$skipped,'failed'=>$failed,'reasons'=>$reasons,'actor'=>documents_quote_import_admin_snapshot(),'time'=>documents_quote_import_now()]; }
